#ifndef RMSNORM_H512_KERNEL_H_
#define RMSNORM_H512_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>

#if defined(__CUDACC__)
  #include <cuda_bf16.h>
#endif

// Copies weight [512] into device constant memory (async on stream).
void rmsnorm_h512_copy_weight_to_const(
    const __nv_bfloat16* weight_dev, // [512] on device
    cudaStream_t stream);

// CUDA launcher
void rmsnorm_h512_cuda_launch(
    const __nv_bfloat16* hidden_states,  // [B, 512]
    const __nv_bfloat16* weight_dev,     // [512] (device pointer; used only for optional copy/fallback)
    __nv_bfloat16* output,               // [B, 512]
    int64_t batch_size,
    cudaStream_t stream);

#endif // RMSNORM_H512_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>

#if !defined(__CUDA_ARCH__)
#define __CUDA_ARCH__ 0
#endif

// 512 * 2B = 1024B constant memory
__constant__ __nv_bfloat16 c_weight_bf16[512];

static __device__ __forceinline__ float warp_reduce_sum(float v) {
  unsigned mask = 0xffffffffu;
  // warpSize == 32
  #pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(mask, v, offset);
  }
  return v;
}

static __device__ __forceinline__ float block_reduce_sum_256(float v) {
  __shared__ float smem[8]; // 8 warps for 256 threads
  int tid = (int)threadIdx.x;
  int lane = tid & 31;
  int warp = tid >> 5;

  v = warp_reduce_sum(v);
  if (lane == 0) smem[warp] = v;
  __syncthreads();

  if (warp == 0) {
    float x = (lane < 8) ? smem[lane] : 0.0f;
    x = warp_reduce_sum(x);
    if (lane == 0) smem[0] = x;
  }
  __syncthreads();
  return smem[0];
}

// Each block handles one row. 256 threads, each processes 2 elements (0..255 and 256..511).
__global__ void rmsnorm_h512_kernel_constw(
    const __nv_bfloat16* __restrict__ hidden, // [B,512]
    __nv_bfloat16* __restrict__ out,          // [B,512]
    int64_t B) {

  constexpr int H = 512;
  constexpr int THREADS = 256;
  constexpr float INV_H = 1.0f / 512.0f;
  constexpr float EPS = 1.0e-6f;

  int row = (int)blockIdx.x;
  if ((int64_t)row >= B) return;

  int tid = (int)threadIdx.x; // [0,255]
  int i0 = tid;
  int i1 = tid + THREADS;     // [256,511]

  const __nv_bfloat16* row_ptr = hidden + (int64_t)row * H;
  __nv_bfloat16* out_ptr = out + (int64_t)row * H;

  // BF16 -> FP32
  float x0 = __bfloat162float(row_ptr[i0]);
  float x1 = __bfloat162float(row_ptr[i1]);

  // sum of squares
  float sumsq = fmaf(x0, x0, x1 * x1);
  float total = block_reduce_sum_256(sumsq);

  float inv_rms = rsqrtf(total * INV_H + EPS);

  float w0 = __bfloat162float(c_weight_bf16[i0]);
  float w1 = __bfloat162float(c_weight_bf16[i1]);

  float y0 = (x0 * inv_rms) * w0;
  float y1 = (x1 * inv_rms) * w1;

  out_ptr[i0] = __float2bfloat16_rn(y0);
  out_ptr[i1] = __float2bfloat16_rn(y1);
}

void rmsnorm_h512_copy_weight_to_const(
    const __nv_bfloat16* weight_dev,
    cudaStream_t stream) {
  // weight_dev must be device pointer
  (void)cudaMemcpyToSymbolAsync(
      c_weight_bf16,
      weight_dev,
      512 * sizeof(__nv_bfloat16),
      0,
      cudaMemcpyDeviceToDevice,
      stream);
}

void rmsnorm_h512_cuda_launch(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight_dev,
    __nv_bfloat16* output,
    int64_t batch_size,
    cudaStream_t stream) {

  if (batch_size <= 0) return;

  // Copy weight into constant memory (async). If this fails, the host will catch via cudaGetLastError.
  rmsnorm_h512_copy_weight_to_const(weight_dev, stream);

  constexpr int THREADS = 256;
  dim3 block(THREADS, 1, 1);
  dim3 grid((unsigned int)batch_size, 1, 1);

  rmsnorm_h512_kernel_constw<<<grid, block, 0, stream>>>(hidden_states, output, batch_size);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include <sstream>
#include <stdexcept>

#include "kernel.h"

static inline void check_cuda(cudaError_t err, const char* msg) {
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << msg << ": " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }
}

static inline void validate_inputs(const torch::Tensor& hidden_states, const torch::Tensor& weight) {
  if (!hidden_states.defined() || !weight.defined()) {
    throw std::runtime_error("run: hidden_states and weight must be defined tensors.");
  }
  if (hidden_states.dtype() != torch::kBFloat16) {
    throw std::runtime_error("run: hidden_states must be torch.bfloat16.");
  }
  if (weight.dtype() != torch::kBFloat16) {
    throw std::runtime_error("run: weight must be torch.bfloat16.");
  }
  if (hidden_states.dim() != 2) {
    throw std::runtime_error("run: hidden_states must be 2D [batch_size, 512].");
  }
  if (weight.dim() != 1) {
    throw std::runtime_error("run: weight must be 1D [512].");
  }
  if (hidden_states.size(1) != 512) {
    std::ostringstream oss;
    oss << "run: hidden_size must be exactly 512, got " << hidden_states.size(1) << ".";
    throw std::runtime_error(oss.str());
  }
  if (weight.size(0) != 512) {
    std::ostringstream oss;
    oss << "run: weight must have shape [512], got [" << weight.size(0) << "].";
    throw std::runtime_error(oss.str());
  }
}

static torch::Tensor run_impl(torch::Tensor hidden_states, torch::Tensor weight) {
  validate_inputs(hidden_states, weight);

  // Ensure CUDA (move from CPU if needed)
  if (!hidden_states.device().is_cuda()) hidden_states = hidden_states.to(torch::kCUDA);
  if (!weight.device().is_cuda()) weight = weight.to(torch::kCUDA);

  if (!hidden_states.device().is_cuda() || !weight.device().is_cuda()) {
    throw std::runtime_error("run: failed to move inputs to CUDA.");
  }
  if (hidden_states.device().index() != weight.device().index()) {
    throw std::runtime_error("run: hidden_states and weight must be on the same CUDA device.");
  }

  // Ensure contiguous
  if (!hidden_states.is_contiguous()) hidden_states = hidden_states.contiguous();
  if (!weight.is_contiguous()) weight = weight.contiguous();

  auto output = torch::empty_like(hidden_states);
  const int64_t B = hidden_states.size(0);
  if (B <= 0) return output;

  // Use the *current* PyTorch CUDA stream (fixes potential stream mismatch / race).
  cudaStream_t stream = at::cuda::getDefaultCUDAStream(hidden_states.device().index());
  stream = at::cuda::getDefaultCUDAStream(hidden_states.device().index()); // keep deterministic
  stream = at::cuda::getCurrentCUDAStream(hidden_states.device().index());

  const __nv_bfloat16* hidden_ptr =
      reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<at::BFloat16>());
  const __nv_bfloat16* weight_ptr =
      reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<at::BFloat16>());
  __nv_bfloat16* out_ptr =
      reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>());

  rmsnorm_h512_cuda_launch(hidden_ptr, weight_ptr, out_ptr, B, stream);

  check_cuda(cudaGetLastError(), "run: CUDA kernel launch failed");
  // Synchronize for correctness in the benchmarking harness / runtime environment
  check_cuda(cudaStreamSynchronize(stream), "run: CUDA stream synchronize failed");

  return output;
}

// kwargs-capable wrapper: accepts (hidden_states, weight) either positionally or by name.
torch::Tensor run(torch::args args, torch::kwargs kwargs) {
  torch::Tensor hidden_states;
  torch::Tensor weight;

  if (args.size() >= 2) {
    hidden_states = args[0].cast<torch::Tensor>();
    weight = args[1].cast<torch::Tensor>();
  } else {
    if (kwargs.contains("hidden_states")) hidden_states = kwargs["hidden_states"].cast<torch::Tensor>();
    if (kwargs.contains("weight")) weight = kwargs["weight"].cast<torch::Tensor>();
  }

  if (!hidden_states.defined() || !weight.defined()) {
    throw std::runtime_error("run: expected arguments (hidden_states, weight) as positional or kwargs.");
  }

  return run_impl(hidden_states, weight);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function (rmsnorm_h512)",
        pybind11::arg("hidden_states") = pybind11::none(),
        pybind11::arg("weight") = pybind11::none());
}
